#!/usr/bin/env python3
import argparse
import sys
from pathlib import Path


def count_lines(words):
    return sum(len(word.split("\n")) - 1 for word in words)


def count_words(words):
    return sum(len(word.split()) for word in words)


def count_chars(words):
    return sum(len(word) for word in words)


def count_file(filepath):
    try:
        with open(filepath, "r") as f:
            words = f.readlines()
    except FileNotFoundError:
        print(f"wordcount.py: {filepath}: No such file or directory")
        return None, None, None

    lines = count_lines(words)
    word_count = count_words(words)
    chars = count_chars(words)
    return lines, word_count, chars


def main():
    parser = argparse.ArgumentParser(
        description="Count lines, words, and characters in files"
    )
    parser.add_argument("files", metavar="FILE", nargs="+", help="Input file(s)")
    parser.add_argument("-l", "--lines", action="store_true", help="Count lines")
    parser.add_argument("-w", "--words", action="store_true", help="Count words")
    parser.add_argument("-c", "--chars", action="store_true", help="Count characters")

    args = parser.parse_args()

    if not (args.lines or args.words or args.chars):
        args.lines = True
        args.words = True
        args.chars = True

    total_lines = 0
    total_words = 0
    total_chars = 0
    success = True

    for filepath in args.files:
        lines, words, chars = count_file(filepath)
        if lines is None or words is None or chars is None:
            success = False
            continue

        total_lines += lines
        total_words += words
        total_chars += chars

        if args.lines:
            print(f"{lines}", end="\t")
        if args.words:
            print(f"{words}", end="\t")
        if args.chars:
            print(f"{chars}", end="\t")
        print(f"{filepath}")

    if len(args.files) > 1:
        if args.lines:
            print(f"{total_lines}", end="\t")
        if args.words:
            print(f"{total_words}", end="\t")
        if args.chars:
            print(f"{total_chars}", end="\t")
        print("total")

    return 1 if not success else 0


if __name__ == "__main__":
    sys.exit(main())
